const headers = ["Booking ID","Submitted At","Appointment Type","Status","Meeting Date","Start Time","End Time","Time Zone","Full Name","Email","Phone","Normalized Phone","Business Name","Business Website","Service Interested In","Budget Range","Project Details","Where Did You Hear About Us?","Lead Source Details","Preferred Contact Method","Additional Participants","Agreement Accepted","Agreement Version","Agreement Timestamp","Conflict Detected","Calendar Event Created","Calendar Event Link","Google Meet Link","Calendar Event ID","Client Confirmation Sent","Team Email Sent","Telegram Notification Sent","Rescheduled From","Cancellation Reason","Internal Notes","Assigned To","Last Updated At","Updated By","Submission Source","UTM Source","UTM Medium","UTM Campaign","UTM Content","UTM Term","Landing Page","Referrer","IP Address","User Agent","Automation Version","Processing Error","Submission ID (internal)","Status Change Processed","Retry Count"];
const rows = $input.first().json.values || [];
return rows.map((r, i) => {
  const obj = {};
  headers.forEach((h, idx) => { obj[h] = r[idx] !== undefined ? r[idx] : ""; });
  obj.rowNumber = i + 2;
  return { json: obj };
});

const actionable = ['Done', 'Cancelled', 'Rescheduled'];
return $input.all().filter(item => {
  const status = item.json['Status'];
  const lastProcessed = item.json['Status Change Processed'];
  return actionable.includes(status) && status !== lastProcessed;
});

const j = $input.first().json;
const timezone = j['Time Zone'] || 'America/Toronto' || 'America/Toronto';
const durationMin = Number(60 || 60);

function timeZoneOffsetMinutes(instant, timeZone) {
  const dtf = new Intl.DateTimeFormat('en-US', { timeZone, hourCycle: 'h23', year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit', second: '2-digit' });
  const parts = dtf.formatToParts(instant).reduce((acc, p) => { acc[p.type] = p.value; return acc; }, {});
  const asUtc = Date.UTC(+parts.year, +parts.month - 1, +parts.day, +parts.hour, +parts.minute, +parts.second);
  return (asUtc - instant.getTime()) / 60000;
}
function zonedTimeToUtc(isoDate, hour, minute, timeZone) {
  const guess = new Date(`${isoDate}T${String(hour).padStart(2,'0')}:${String(minute).padStart(2,'0')}:00Z`);
  const offset = timeZoneOffsetMinutes(guess, timeZone);
  return new Date(guess.getTime() - offset * 60000);
}

const [_, hh, mm, ampm] = j['Start Time'].match(/(\d+):(\d+)\s*(AM|PM)/i);
let hour = parseInt(hh, 10) % 12;
if (/PM/i.test(ampm)) hour += 12;
const start = zonedTimeToUtc(j['Meeting Date'], hour, parseInt(mm, 10), timezone);
const end = new Date(start.getTime() + durationMin * 60000);

return [{ json: { ...j, newStartIso: start.toISOString(), newEndIso: end.toISOString() } }];

